#!/usr/bin/env pwsh
$basedir=Split-Path $MyInvocation.MyCommand.Definition -Parent

$exe=""
$pathsep=":"
$env_node_path=$env:NODE_PATH
$new_node_path="C:\gemini-cli\workflow pro builder\node_modules\.pnpm\pino-sentry@0.15.0\node_modules\pino-sentry\dist\node_modules;C:\gemini-cli\workflow pro builder\node_modules\.pnpm\pino-sentry@0.15.0\node_modules\pino-sentry\node_modules;C:\gemini-cli\workflow pro builder\node_modules\.pnpm\pino-sentry@0.15.0\node_modules;C:\gemini-cli\workflow pro builder\node_modules\.pnpm\node_modules"
if ($PSVersionTable.PSVersion -lt "6.0" -or $IsWindows) {
  # Fix case when both the Windows and Linux builds of Node
  # are installed in the same directory
  $exe=".exe"
  $pathsep=";"
} else {
  $new_node_path="/mnt/c/gemini-cli/workflow pro builder/node_modules/.pnpm/pino-sentry@0.15.0/node_modules/pino-sentry/dist/node_modules:/mnt/c/gemini-cli/workflow pro builder/node_modules/.pnpm/pino-sentry@0.15.0/node_modules/pino-sentry/node_modules:/mnt/c/gemini-cli/workflow pro builder/node_modules/.pnpm/pino-sentry@0.15.0/node_modules:/mnt/c/gemini-cli/workflow pro builder/node_modules/.pnpm/node_modules"
}
if ([string]::IsNullOrEmpty($env_node_path)) {
  $env:NODE_PATH=$new_node_path
} else {
  $env:NODE_PATH="$new_node_path$pathsep$env_node_path"
}

$ret=0
if (Test-Path "$basedir/node$exe") {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "$basedir/node$exe"  "$basedir/../pino-sentry/dist/cli.js" $args
  } else {
    & "$basedir/node$exe"  "$basedir/../pino-sentry/dist/cli.js" $args
  }
  $ret=$LASTEXITCODE
} else {
  # Support pipeline input
  if ($MyInvocation.ExpectingInput) {
    $input | & "node$exe"  "$basedir/../pino-sentry/dist/cli.js" $args
  } else {
    & "node$exe"  "$basedir/../pino-sentry/dist/cli.js" $args
  }
  $ret=$LASTEXITCODE
}
$env:NODE_PATH=$env_node_path
exit $ret
